/*
 * Design system variables – derived from the provided color scheme and screenshot
 * The visual style mirrors a classic web‑2.0 academic journal layout (strong blue gradients,
 * rounded cards, dense text).
 */

:root {
    /* Primary blues (header / navigation) */
    --color-primary-dark: #0057C8;  /* deep header/nav blue */
    --color-primary: #007FEF;       /* bright mid blue */
    --color-primary-light: #00A5E0; /* lighter cyan accent */

    /* Secondary / accent */
    --color-secondary-green: #2E7D32; /* deep green */
    --color-accent-green: #44B749;    /* vivid CTA green */

    /* Neutrals */
    --color-white: #FFFFFF;
    --color-page-bg: #F5F5F5;
    --color-border-subtle: #DDDDDD;
    --color-text-main: #222222;
    --color-text-muted: #666666;

    /* Semantic (not all used in the framework, but available site‑wide) */
    --color-success: #44B749;
    --color-error: #D32F2F;
    --color-warning: #FFC107;
    --color-info: #0288D1;

    /* Greys for search/button skeuomorphic look */
    --color-grey-medium: #888888;
    --color-grey-light: #BDBDBD;
    --color-grey-xlight: #EEEEEE;

    /* Typography */
    --font-family-base: "Tahoma", "Verdana", "Segoe UI", Arial, sans-serif;
    --font-size-body: 14px;
    --font-size-small: 12px;
    --font-size-h1: 24px;
    --font-size-h2: 18px;
    --font-size-h3: 16px;
    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing scale (approx. 4px baseline) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 20px;
    --space-6: 24px;
    --space-7: 32px;
    --space-8: 40px;

    /* Layout */
    --container-max-width: 1180px;
    --border-radius-card: 10px;
    --border-radius-button: 5px;
}

/* Global resets / base styles */

*,
*::before,
*::after {
    box-sizing: border-box;
}

html {
    font-size: 100%;
}

body {
    margin: 0;
    padding: 0;
    font-family: var(--font-family-base);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-text-main);
    background-color: var(--color-page-bg);
}

img {
    max-width: 100%;
    height: auto;
    border: 0;
}

a {
    color: var(--color-primary-dark);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

.page-shell {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.container {
    width: 100%;
    max-width: var(--container-max-width);
    margin: 0 auto;
    padding-left: var(--space-4);
    padding-right: var(--space-4);
}

.site-main {
    flex: 1 0 auto;
    padding-top: var(--space-7);
    padding-bottom: var(--space-7);
}

/* Screen-reader only utility */

.sr-only {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    border: 0;
}

/* Header: masthead */

.site-header {
    flex: 0 0 auto;
}

.masthead {
    background: linear-gradient(90deg, var(--color-primary-dark) 0%, var(--color-primary) 40%, var(--color-primary-light) 100%);
    /* soft glossy overlay */
    background-image:
        linear-gradient(to bottom, rgba(255, 255, 255, 0.35) 0, rgba(255, 255, 255, 0) 40%),
        linear-gradient(90deg, var(--color-primary-dark) 0%, var(--color-primary) 40%, var(--color-primary-light) 100%);
    color: var(--color-white);
    padding-top: var(--space-4);
    padding-bottom: var(--space-4);
}

.masthead-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.brand {
    display: flex;
    align-items: center;
    text-decoration: none;
    color: inherit;
}

.brand-mark {
    width: 86px;
    height: 70px;
    border-radius: 12px;
    background: radial-gradient(circle at 30% 20%, #ffffff 0%, rgba(255, 255, 255, 0) 40%),
                radial-gradient(circle at 70% 80%, rgba(255, 255, 255, 0.6) 0%, rgba(255, 255, 255, 0) 55%),
                linear-gradient(135deg, #003f9e 0%, #007FEF 50%, #00A5E0 100%);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: var(--space-4);
    box-shadow: 0 0 0 2px rgba(255, 255, 255, 0.65);
}

.brand-mark-text {
    font-size: 26px;
    font-weight: bold;
    letter-spacing: 1px;
    text-shadow: 0 1px 2px rgba(0, 0, 0, 0.5);
}

.brand-text {
    display: flex;
    flex-direction: column;
}

.site-title {
    font-size: 22px;
    font-weight: bold;
    letter-spacing: 0.4px;
    margin-bottom: 2px;
    text-shadow: 0 1px 1px rgba(0, 0, 0, 0.45);
}

.site-subtitle {
    font-size: 13px;
    font-weight: normal;
    opacity: 0.95;
}

.masthead-meta {
    text-align: right;
    max-width: 320px;
}

.masthead-org {
    font-size: 15px;
    font-weight: bold;
    text-shadow: 0 1px 1px rgba(0, 0, 0, 0.45);
}

.masthead-org-subtitle {
    margin-top: 3px;
    font-size: 12px;
}

/* Primary navigation bar */

.primary-nav-bar {
    background: linear-gradient(to bottom, #0061d4 0%, #0050b5 50%, #00449a 100%);
    border-bottom: 1px solid #003b87;
}

.primary-nav-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
}

.primary-nav {
    flex: 1 1 auto;
}

.primary-nav-list {
    list-style: none;
    display: flex;
    align-items: center;
    margin: 0;
    padding: 0;
}

.nav-item + .nav-item {
    margin-left: var(--space-4);
}

.nav-item a {
    display: block;
    padding: 8px 10px;
    color: var(--color-white);
    font-size: 14px;
    font-weight: bold;
    text-shadow: 0 1px 1px rgba(0, 0, 0, 0.5);
    border-radius: 3px;
}

.nav-item a:hover,
.nav-item a:focus {
    background: linear-gradient(to bottom, rgba(255, 255, 255, 0.35) 0%, rgba(255, 255, 255, 0.15) 100%);
    text-decoration: none;
}

/* Search form in header */

.header-search {
    flex: 0 0 auto;
    display: flex;
    align-items: center;
    margin-left: var(--space-5);
}

.search-input {
    width: 260px;
    height: 34px;
    padding: 0 var(--space-3);
    border-radius: 4px 0 0 4px;
    border: 1px solid #bbbbbb;
    outline: none;
    font-size: 13px;
}

.search-input:focus {
    border-color: var(--color-primary-light);
    box-shadow: 0 0 0 1px rgba(0, 165, 224, 0.45);
}

.search-button {
    height: 34px;
    padding: 0 var(--space-4);
    border: 1px solid #7a7a7a;
    border-left: 0;
    border-radius: 0 4px 4px 0;
    background: linear-gradient(to bottom, #B0B0B0 0%, #8C8C8C 100%);
    color: var(--color-white);
    font-size: 13px;
    font-weight: bold;
    cursor: pointer;
    text-shadow: 0 1px 1px rgba(0, 0, 0, 0.4);
}

.search-button:hover,
.search-button:focus {
    background: linear-gradient(to bottom, #C2C2C2 0%, #999999 100%);
}

/* Card component – matches the white rounded cards in the main content */

.card {
    background-color: var(--color-white);
    border-radius: var(--border-radius-card);
    border: 1px solid var(--color-border-subtle);
    padding: 0;
    margin-bottom: var(--space-6);
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
}

.card-header {
    border-radius: var(--border-radius-card) var(--border-radius-card) 0 0;
    padding: 8px 14px;
    background: linear-gradient(to bottom, var(--color-primary) 0%, var(--color-primary-dark) 100%);
    color: var(--color-white);
    font-size: var(--font-size-h3);
    font-weight: bold;
    text-shadow: 0 1px 1px rgba(0, 0, 0, 0.5);
}

.card-body {
    padding: var(--space-5);
}

.card-section-row {
    padding-top: 6px;
    padding-bottom: 6px;
    border-bottom: 1px solid var(--color-border-subtle);
    font-size: 13px;
}

.card-section-row:last-child {
    border-bottom: 0;
}

/* Footer styling */

.site-footer {
    flex: 0 0 auto;
    font-size: var(--font-size-small);
    color: var(--color-white);
}

.footer-top {
    background: linear-gradient(to bottom, #0050b5 0%, #00449a 50%, #00387f 100%);
    border-top: 3px solid #007FEF;
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
}

.footer-top-inner {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-6);
}

.footer-column {
    min-width: 180px;
}

.footer-column-wide {
    flex: 1 1 260px;
}

.footer-heading {
    margin: 0 0 var(--space-3) 0;
    font-size: var(--font-size-h3);
    font-weight: bold;
    text-shadow: 0 1px 1px rgba(0, 0, 0, 0.5);
}

.footer-text {
    margin: 0;
    line-height: var(--line-height-relaxed);
}

.footer-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
}

.footer-nav-list li + li {
    margin-top: 2px;
}

.footer-nav-list a {
    color: var(--color-white);
}

.footer-nav-list a:hover,
.footer-nav-list a:focus {
    text-decoration: underline;
}

.footer-bottom {
    background: #002955;
    border-top: 1px solid #001b37;
}

.footer-bottom-inner {
    padding-top: var(--space-3);
    padding-bottom: var(--space-3);
    text-align: center;
}

.footer-copy {
    margin: 0;
}

/* Simple responsiveness for narrower screens */

@media (max-width: 960px) {
    .masthead-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-3);
    }

    .masthead-meta {
        text-align: left;
        max-width: 100%;
    }

    .primary-nav-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-3);
    }

    .header-search {
        margin-left: 0;
    }
}

@media (max-width: 640px) {
    .primary-nav-list {
        flex-wrap: wrap;
        row-gap: var(--space-2);
    }

    .nav-item {
        margin-right: var(--space-2);
    }

    .search-input {
        width: 190px;
    }
}
